    <TargetFramework>net10.0</TargetFramework>
    <ImplicitUsings>enable</ImplicitUsings>
    <Nullable>enable</Nullable>
  </PropertyGroup>
  <ItemGroup>
    <ProjectReference Include="$repo/src/MudBlazor/MudBlazor.csproj" />
  </ItemGroup>
</Project>
EOF
cat > "$work/Program.cs" <<'CS'
using System.Reflection;
using Microsoft.AspNetCore.Components;
using MudBlazor;

var tabsDisabled = typeof(MudTabs).GetProperty("Disabled", BindingFlags.Instance | BindingFlags.Public);
if (tabsDisabled is null)
{
    Console.Error.WriteLine("FAIL: MudTabs does not expose a public Disabled property.");
    return 1;
}

if (tabsDisabled.PropertyType != typeof(bool) || !tabsDisabled.GetCustomAttributes(typeof(ParameterAttribute), inherit: true).Any())
{
    Console.Error.WriteLine("FAIL: MudTabs.Disabled must be a bool [Parameter].");
    return 1;
}

var isPanelDisabled = typeof(MudTabs).GetMethod("IsPanelDisabled", BindingFlags.Instance | BindingFlags.NonPublic | BindingFlags.Public);
if (isPanelDisabled is null)
{
    Console.Error.WriteLine("FAIL: MudTabs does not have an effective disabled-state helper.");
    return 1;
}

bool Effective(MudTabs tabs, MudTabPanel panel) => (bool)isPanelDisabled.Invoke(tabs, [panel])!;

var tabs = new MudTabs();
var panel = new MudTabPanel();
if (Effective(tabs, panel))
{
    Console.Error.WriteLine("FAIL: panel should be enabled when neither parent nor child is disabled.");
    return 1;
}

panel.Disabled = true;
if (!Effective(tabs, panel))
{
    Console.Error.WriteLine("FAIL: child Disabled=true should disable the panel.");
    return 1;
}

panel.Disabled = false;
tabs.Disabled = true;
if (!Effective(tabs, panel))
{
    Console.Error.WriteLine("FAIL: parent MudTabs.Disabled=true should disable the child panel.");
    return 1;
}

panel.Disabled = true;
if (!Effective(tabs, panel))
{
    Console.Error.WriteLine("FAIL: parent and child Disabled=true should keep the panel disabled.");
    return 1;
}

Console.WriteLine("PASS: MudTabs.Disabled exists and contributes to effective panel disabled state.");
return 0;
CS
